### Backend: metodo get_detail_data en pest.trap
def get_detail_data(self):
    self.ensure_one()
    incidents = self.env['pest.incident'].search_read(
        [('trap_id', '=', self.id)],
        ['date', 'plague_type_id', 'incident_type', 'organism_count', 'notes'],
        limit=10, order='date desc')
    states = self.env['pest.trap.state'].search_read(
        [('trap_id', '=', self.id)],
        ['date', 'state', 'observations', 'user_id'],
        limit=5, order='date desc')
    return {
        'trap_name': self.name,
        'trap_type': self.trap_type_id.name if self.trap_type_id else '',
        'location': self.location or '',
        'current_state': self.current_state,
        'incidents': [{
            'date': str(i['date'] or ''),
            'plague': i['plague_type_id'][1] if i.get('plague_type_id') else '',
            'type': i.get('incident_type', ''),
            'count': i.get('organism_count', 0),
            'notes': i.get('notes', ''),
        } for i in incidents],
        'states': [{
            'date': str(s['date'] or ''),
            'state': s.get('state', ''),
            'observations': s.get('observations', ''),
            'user': s['user_id'][1] if s.get('user_id') else '',
        } for s in states],
    }

### Frontend JS: cargar detalle al seleccionar trampa
Agregar estado trapDetail: null al useState.
Cuando selectedTrapId cambia (en onTrapMarkerClick), cargar detalle:

async onTrapMarkerClick(ev, trap) {
    ev.stopPropagation();
    if (this.state.selectedTrapId === trap.id) {
        this.state.selectedTrapId = null;
        this.state.trapDetail = null;
        return;
    }
    this.state.selectedTrapId = trap.id;
    // Load detail data
    try {
        const detail = await this.orm.call('pest.trap', 'get_detail_data', [[trap.id]]);
        this.state.trapDetail = detail;
    } catch (e) {
        this.state.trapDetail = null;
    }
}

